insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:5-3-revenue-costs-profit-loss:learn:23a8c92c', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'learn', 'mcq', 1, '{"readingTitle": "Revenue — Formula & Decision Making", "reading": "<p><strong>Revenue</strong> is the income coming into a business from the sale of products and services. It is NOT the same as profit.</p>\n    <div class=\"formula-box\">\n      <strong>Revenue = Quantity Sold × Selling Price</strong>\n    </div>\n    <p>Example: A business sells 25 cars at £7,500 each → TR = 25 × £7,500 = <strong>£187,500</strong></p>\n    <p>Revenue must be analysed carefully before making pricing decisions. Simply cutting the price does not guarantee higher revenue — you must calculate total revenue at each price point.</p>\n    <ul>\n    <li><strong>Raise price:</strong> Earns more per unit but may lose customers. Works when competitors are few.</li>\n    <li><strong>Lower price:</strong> Sells more units but earns less each. Works when demand is price-sensitive.</li>\n    <li><strong>Increase advertising:</strong> Can drive more sales, but the extra revenue must exceed the cost of advertising.</li>\n    <li><strong>Expand product range:</strong> More products attract more customers (e.g. Dyson, Tesco, Amazon).</li>\n    <li><strong>Open new markets / e-commerce:</strong> Reaches customers globally without high fixed costs.</li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">Factors That Increase Revenue</div>\n    <div class=\"pro-item\"><strong>Fewer competitors:</strong> A business can raise prices without losing customers to rivals.</div>\n    <div class=\"pro-item\"><strong>Competitor price rises:</strong> Allows you to raise prices too without losing market share.</div>\n    <div class=\"pro-item\"><strong>Product is already cheap:</strong> A percentage price rise has little impact on demand and boosts revenue.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">Factors That May Reduce Revenue</div>\n    <div class=\"con-item\"><strong>Many competitors:</strong> Customers switch, reducing sales volume and revenue.</div>\n    <div class=\"con-item\"><strong>Competitor price cuts:</strong> You may need to match them or lose customers.</div>\n    <div class=\"con-item\"><strong>Premium-priced products:</strong> Any further price rise may significantly reduce demand.</div>\n    </div>\n    </div>", "question": "According to this card, what must a business do before assuming a price cut will raise revenue?", "options": ["Calculate total revenue at each price point rather than assuming", "Wait until its net profit margin has doubled compared with last year", "Automatically raise prices to match its main competitors", "Reduce its total fixed costs before changing any prices"]}'::jsonb, '{"answer": 0, "explain": "The card warns that cutting price does not guarantee higher revenue — a business must calculate total revenue at each price point before deciding."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:learn:fc19d98d', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'learn', 'mcq', 1, '{"readingTitle": "Fixed Costs vs Variable Costs", "reading": "<p>Every cost a business pays falls into one of two categories. Getting this distinction right is essential for exam questions on costs, break-even and profit.</p>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">Fixed Costs</div>\n    <div class=\"pro-item\"><strong>Do NOT change</strong> when output changes. Must be paid whether the business produces 0 or 10,000 units.</div>\n    <div class=\"pro-item\"><strong>Examples:</strong> Rent, business rates, insurance, <em>salaries</em>, interest on loans, mortgage payments, advertising (if contracted).</div>\n    <div class=\"pro-item\"><strong>Key fact:</strong> Even if a business temporarily closes, fixed costs continue.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">Variable Costs</div>\n    <div class=\"con-item\"><strong>DO change</strong> when output changes. The more the business produces, the higher the total variable cost.</div>\n    <div class=\"con-item\"><strong>Examples:</strong> Raw materials, <em>wages</em> (hourly paid), packaging, energy used in production, stock purchased to resell.</div>\n    <div class=\"con-item\"><strong>Formula:</strong> Total Variable Costs = Quantity × Variable Cost per Unit</div>\n    </div>\n    </div>\n    <p>⚠️ <strong>Salaries vs Wages:</strong> Salaries (fixed annual pay) = fixed cost. Hourly wages (paid per hour worked) = variable cost.</p>\n    <div class=\"formula-box\">\n      <strong>Total Costs (TC) = Total Fixed Costs (TFC) + Total Variable Costs (TVC)</strong>\n    </div>\n    <p><strong>Worked Example:</strong> Fixed costs = £18,000/month. Variable cost per unit = £2.75. Units sold = 5,450.<br>\n    TVC = 5,450 × £2.75 = £14,987.50 &nbsp; TC = £18,000 + £14,987.50 = <strong>£32,987.50</strong></p>", "question": "According to this card, how are salaries and hourly wages classified?", "options": ["Salaries are a fixed cost, while hourly wages are a variable cost", "Both salaries and hourly wages are always classed as fixed costs", "Both salaries and hourly wages are always classed as variable costs", "Salaries are a variable cost, while hourly wages are a fixed cost"]}'::jsonb, '{"answer": 0, "explain": "The card explains salaries (fixed annual pay) are a fixed cost, while hourly wages (paid per hour worked) are a variable cost — a key exam distinction."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:learn:8159b002', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'learn', 'mcq', 1, '{"readingTitle": "Gross Profit and Net Profit", "reading": "<p>There are two types of profit. Both are calculated differently and tell you different things about a business.</p>\n    <div class=\"formula-box\">\n      <strong>Gross Profit = Revenue − Cost of Sales</strong>\n    </div>\n    <p>Gross profit measures the profit from buying and selling goods <em>before</em> the running costs of the business are deducted. Example: buy goods for £30, sell for £50 → Gross profit = £20.</p>\n    <div class=\"formula-box\">\n      <strong>Net Profit = Gross Profit − Expenses</strong>\n    </div>\n    <p>Net profit is a more accurate measure because it accounts for ALL costs. Example:</p>\n    <ul>\n    <li>Gross profit: £500,000</li>\n    <li>Wages &amp; salaries: £300,000 &nbsp;|&nbsp; Rent: £50,000 &nbsp;|&nbsp; Heating: £10,000 &nbsp;|&nbsp; Insurance: £5,000 = Total expenses: £365,000</li>\n    <li><strong>Net profit = £500,000 − £365,000 = £135,000</strong></li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ When Profit Rises...</div>\n    <div class=\"pro-item\">Buy new equipment and buildings</div>\n    <div class=\"pro-item\">Expand or take over other businesses</div>\n    <div class=\"pro-item\">Pay increasing dividends to shareholders</div>\n    <div class=\"pro-item\">Develop new products and services</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ When Losses Occur...</div>\n    <div class=\"con-item\">Investment decisions postponed</div>\n    <div class=\"con-item\">May be forced to accept a takeover</div>\n    <div class=\"con-item\">Dividends reduced or cancelled</div>\n    <div class=\"con-item\">Cannot invest in new products — loses customers to rivals</div>\n    </div>\n    </div>", "question": "What happens to a business''s spending options when it makes a loss, according to this card?", "options": ["The business can automatically raise its dividends paid to shareholders", "Investment decisions may be postponed and dividends reduced or cancelled", "The business must immediately increase its net profit margin", "The business is guaranteed to be taken over by a competitor firm"]}'::jsonb, '{"answer": 1, "explain": "The card lists postponed investment and reduced or cancelled dividends as consequences of a loss — the opposite of what happens when profit rises."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:learn:a48289b9', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'learn', 'mcq', 1, '{"readingTitle": "Profitability Ratios — GPM & NPM", "reading": "<p>Profitability ratios allow a business to <strong>measure and compare performance</strong> more accurately than just looking at profit figures. A rising profit can still mean falling profitability if revenue rises faster.</p>\n    <div class=\"formula-box\">\n      <strong>Gross Profit Margin (%) = (Gross Profit ÷ Revenue) × 100</strong>\n    </div>\n    <div class=\"formula-box\">\n      <strong>Net Profit Margin (%) = (Net Profit ÷ Revenue) × 100</strong>\n    </div>\n    <p><strong>Example — Jacquelyn Williams Booksellers:</strong></p>\n    <ul>\n    <li>Year 1: Revenue £150,000 | Gross Profit £70,000 | Net Profit £30,000</li>\n    <li>Year 2: Revenue £225,000 | Gross Profit £85,000 | Net Profit £30,000</li>\n    </ul>\n    <p>Year 1 GPM = (70,000 ÷ 150,000) × 100 = <strong>46.7%</strong> &nbsp; Year 2 GPM = (85,000 ÷ 225,000) × 100 = <strong>37.8%</strong></p>\n    <p>Year 1 NPM = (30,000 ÷ 150,000) × 100 = <strong>20%</strong> &nbsp; Year 2 NPM = (30,000 ÷ 225,000) × 100 = <strong>13.3%</strong></p>\n    <p>Although net profit stayed the same in pounds, <strong>both margins fell</strong> — the business is becoming less efficient at converting revenue into profit. Action should be taken.</p>\n    <p>⚠️ <strong>Net profit margin is considered the more accurate profitability measure</strong> because it accounts for ALL costs, not just cost of sales.</p>", "question": "In the Jacquelyn Williams example, what happened to profitability even though net profit in pounds stayed the same?", "options": ["Both the gross and net profit margins rose as revenue fell faster than profit", "Both margins stayed exactly the same because profit in pounds was unchanged", "The gross profit margin rose while the net profit margin stayed the same", "Both the gross and net profit margins fell as revenue rose faster than profit"]}'::jsonb, '{"answer": 3, "explain": "The card shows that although net profit stayed at £30,000, both GPM and NPM fell because revenue rose faster than profit — profitability, not just profit, must be tracked."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:learn:c2d2ab6e', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'learn', 'mcq', 1, '{"readingTitle": "Interpreting Profitability Ratios", "reading": "<p>Being able to calculate a ratio is only the first step. Examiners award the higher marks for interpreting what the figures mean and recommending appropriate action.</p>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">↑ GPM Improves When...</div>\n    <div class=\"pro-item\">Revenue rises faster than cost of sales</div>\n    <div class=\"pro-item\">Revenue falls but cost of sales falls more</div>\n    <div class=\"pro-item\">Revenue rises AND cost of sales falls</div>\n    <div class=\"col-head\" style=\"margin-top:8px\">↑ NPM Improves When...</div>\n    <div class=\"pro-item\">Gross profit rises faster than expenses</div>\n    <div class=\"pro-item\">Gross profit falls but expenses fall more</div>\n    <div class=\"pro-item\">Gross profit rises AND expenses fall</div>\n    </div>\n    <div>\n    <div class=\"col-head\">↓ GPM Worsens When...</div>\n    <div class=\"con-item\">Revenue falls AND cost of sales rises</div>\n    <div class=\"con-item\">Revenue rises but cost of sales rises more</div>\n    <div class=\"con-item\">Revenue falls but cost of sales falls less</div>\n    <div class=\"col-head\" style=\"margin-top:8px\">↓ NPM Worsens When...</div>\n    <div class=\"con-item\">Gross profit falls AND expenses rise</div>\n    <div class=\"con-item\">Gross profit rises but expenses rise more</div>\n    <div class=\"con-item\">Gross profit falls but expenses fall less</div>\n    </div>\n    </div>\n    <p><strong>How to improve GPM:</strong> Increase revenue (adjust pricing, increase advertising, enter new markets) OR reduce cost of sales (negotiate lower supplier prices, find cheaper suppliers).</p>\n    <p><strong>How to improve NPM:</strong> All GPM strategies PLUS reduce expenses — cut the wage bill, save on energy, reduce rent.</p>", "question": "According to this card, when does gross profit margin improve?", "options": ["When fixed costs increase while variable costs stay exactly the same", "When net profit falls but expenses rise even further than that", "When cost of sales rises faster than revenue increases each year", "When revenue rises faster than cost of sales, or cost of sales falls"]}'::jsonb, '{"answer": 3, "explain": "The card lists revenue rising faster than cost of sales (or cost of sales falling) as ways GPM improves — expenses and fixed/variable cost changes affect NPM, not GPM directly."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:learn:aeef0436', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'learn', 'mcq', 1, '{"readingTitle": "Average Rate of Return (ARR)", "reading": "<p>ARR is used to judge whether a business investment (in equipment or another business) is worthwhile, by expressing the average annual profit as a percentage of the original cost.</p>\n    <div class=\"formula-box\">\n      <strong>Step 1: Total Profit = Total Income (from investment) − Cost of Investment</strong><br><br>\n      <strong>Step 2: Average Annual Profit = Total Profit ÷ Life of Investment (years)</strong><br><br>\n      <strong>Step 3: ARR (%) = (Average Annual Profit ÷ Cost of Investment) × 100</strong>\n    </div>\n    <p><strong>Worked Example:</strong> A business buys a mower for £5,000 and earns £13,000 over 5 years.</p>\n    <ul>\n    <li>Step 1: £13,000 − £5,000 = £8,000 total profit</li>\n    <li>Step 2: £8,000 ÷ 5 = £1,600 average annual profit</li>\n    <li>Step 3: (£1,600 ÷ £5,000) × 100 = <strong>32%</strong></li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages of ARR</div>\n    <div class=\"pro-item\">Gives a percentage return easily compared with other investments or savings rates</div>\n    <div class=\"pro-item\">Focuses on profitability — key for shareholders and investors</div>\n    <div class=\"pro-item\">Straightforward to calculate and explain</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages of ARR</div>\n    <div class=\"con-item\">Based on a forecast — actual results may differ significantly</div>\n    <div class=\"con-item\">Does not account for the timing of cash flows</div>\n    <div class=\"con-item\">Ignores the time value of money</div>\n    </div>\n    </div>\n    <p><strong>How ARR is used:</strong> Compare two investments and choose the one with the higher ARR. Compare ARR against a bank interest rate — if ARR is only slightly higher than a risk-free savings rate, the investment may not be worth the risk.</p>", "question": "What is Step 1 of the ARR calculation, according to this card?", "options": ["Divide total income directly by the cost of investment straight away", "Subtract the cost of investment from total income to find total profit", "Multiply the cost of investment by the number of years invested", "Divide the cost of investment by the total annual profit figure"]}'::jsonb, '{"answer": 1, "explain": "The card sets out Step 1 as Total Profit = Total Income − Cost of Investment, before dividing by years (Step 2) and then by cost of investment (Step 3)."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:learn:0178ec15', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'learn', 'mcq', 1, '{"readingTitle": "Revenue, Costs & Profit in Decision Making", "reading": "<p>Financial data is only valuable if it is used to make better business decisions. Each measure of performance has specific implications for what a business should do next.</p>\n    <p><strong>Revenue and Decision Making:</strong> Revenue data helps set pricing strategy. A business must test different price points to find which maximises total revenue. Increasing sales volume through advertising or expansion is another route — but the cost must be outweighed by the revenue gain.</p>\n    <p><strong>Costs and Decision Making:</strong> High fixed costs mean the business must sell many products just to break even. If variable costs rise (e.g. raw materials become more expensive), the business can accept the increase, find a cheaper supplier, or negotiate with the existing one.</p>\n    <p><strong>Profit and Loss in Decision Making:</strong> Sustained profit funds expansion and investment. Losses force cuts. A business that continues to make losses will eventually fail.</p>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Zara (Global Fashion)</h4>\n      <p>Zara keeps its variable costs low by buying fabric in large quantities from European suppliers. This lowers cost of sales and improves gross profit margin. With better margins, Zara''s owners receive more profit. When COVID-19 struck in 2020, Zara''s revenue fell 29% from €19,954m to €14,129m. Its ability to control costs helped it survive the fall. This shows that profitability ratios — not just revenue — are the true test of financial health.</p>\n    </div>", "question": "According to the Zara case study, what helped the business survive its 2020 revenue fall?", "options": ["Closing its stores permanently in every country it traded in", "Controlling costs, which protected its profitability despite falling revenue", "Borrowing heavily from banks to cover its day-to-day running costs", "Raising its selling prices sharply across every single global market it serves"]}'::jsonb, '{"answer": 1, "explain": "The card explains Zara''s low variable costs and controlled cost of sales protected its profit margins when revenue fell 29% in 2020 — showing profitability ratios matter more than revenue alone."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:learn:cc72943e', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'learn', 'mcq', 1, '{"readingTitle": "How to Increase Revenue & Reduce Costs", "reading": "<p>Businesses can improve their profitability from two sides: increasing revenue or reducing costs. Both affect profit margins.</p>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">↑ Strategies to Increase Revenue</div>\n    <div class=\"pro-item\"><strong>Raise selling price:</strong> Works if customers are not very price-sensitive (few alternatives)</div>\n    <div class=\"pro-item\"><strong>Lower price to increase volume:</strong> Works if demand is highly price-sensitive</div>\n    <div class=\"pro-item\"><strong>Increase advertising:</strong> Builds brand awareness and drives sales</div>\n    <div class=\"pro-item\"><strong>Expand product range:</strong> Appeal to more customer segments</div>\n    <div class=\"pro-item\"><strong>Open new markets / sell online:</strong> Reach more customers globally</div>\n    </div>\n    <div>\n    <div class=\"col-head\">↓ Strategies to Reduce Costs</div>\n    <div class=\"con-item\"><strong>Find cheaper suppliers:</strong> Must also check quality and reliability</div>\n    <div class=\"con-item\"><strong>Negotiate lower prices:</strong> Ask existing suppliers for discounts, especially on bulk orders</div>\n    <div class=\"con-item\"><strong>Use technology:</strong> Automate production to reduce labour costs</div>\n    <div class=\"con-item\"><strong>Reduce the wage bill:</strong> Cut hours, reduce pay, or replace labour with machines</div>\n    <div class=\"con-item\"><strong>Save on energy:</strong> More efficient equipment, better insulation</div>\n    </div>\n    </div>", "question": "Which of these is listed as a strategy to reduce costs in this card?", "options": ["Expanding the product range to appeal to new customer segments", "Using technology to automate production and reduce labour costs", "Opening new markets by selling products online internationally", "Raising the selling price charged to existing loyal customers"]}'::jsonb, '{"answer": 1, "explain": "The card lists automating production with technology as a cost-reduction strategy; raising prices, expanding range and opening new markets are all revenue-increasing strategies instead."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:learn:0e71a3f4', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'learn', 'mcq', 1, '{"readingTitle": "Real-World Examples", "reading": "<div class=\"case-study-box\">\n      <h4>Case Study: Alan Cropley Guitars (ACG)</h4>\n      <p>ACG''s guitars were featured at a major music festival in 2016, driving huge demand. Revenue doubled as Alan was able to increase prices. However, he also hired six more skilled workers and the factory was reaching capacity. His financial data (Revenue: £860,000 | Gross Profit: £550,000 | Net Profit: £210,000 | Guitars sold: 520) gives a net profit margin of 24.4%. Alan must consider whether a new factory investment (a higher fixed cost) would be justified by the additional revenue it could generate — this is exactly the kind of decision ARR is designed to support.</p>\n      <p><strong>Takeaway:</strong> Revenue growth does not automatically guarantee rising profitability. Tracking profit margins over time is essential to spot whether costs are rising faster than revenue.</p>\n    </div>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Unilever plc</h4>\n      <p>Unilever sells products including Lynx, Dove, Hellmann''s and Persil across 190 countries. Its worldwide revenue grew from €50,900m (2018) to €60,000m (2022) — but dipped to €50,700m in 2020. Despite revenue growth, Unilever must manage both variable costs (raw materials per product) and fixed costs (factory rent, salaries) to protect its profit margins. This illustrates that revenue trends alone do not tell the full financial story.</p>\n    </div>", "question": "What is the key takeaway from the Alan Cropley Guitars (ACG) case study?", "options": ["Net profit margin is irrelevant whenever a business''s revenue is increasing", "Guitar factories never need to consider fixed costs when they invest", "Revenue growth always guarantees that profitability will also rise too", "Revenue growth does not automatically guarantee that profitability also rises"]}'::jsonb, '{"answer": 3, "explain": "The card''s takeaway is that revenue growth does not automatically mean rising profitability — tracking profit margins over time reveals whether costs are outpacing revenue."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:misc:ec0c2ec4', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Revenue is the same as profit.</p><p><strong>✅ The correct idea:</strong> Revenue is the total income from sales (quantity × price). Profit is what remains AFTER costs are deducted. A business can have high revenue but still make a loss if costs are even higher.</p>", "question": "What is the correct relationship between revenue and profit?", "options": ["Revenue is always exactly equal to a business''s net profit figure", "Profit is calculated by adding all of a business''s costs to revenue", "Revenue and profit are simply two different names for the same figure", "Profit is what remains after all costs are deducted from revenue"]}'::jsonb, '{"answer": 3, "explain": "The card explains revenue is total income from sales, while profit is what remains after costs are deducted — a business can have high revenue but still make a loss."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:misc:cf597369', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If net profit in pounds increases, the net profit margin must also increase.</p><p><strong>✅ The correct idea:</strong> Not necessarily. If revenue grows faster than net profit, the margin actually falls. For example: net profit stays at £30,000 but revenue doubles from £150,000 to £300,000 — the NPM halves from 20% to 10%.</p>", "question": "Why can net profit margin fall even though net profit in pounds stays the same?", "options": ["If revenue grows faster than net profit, the margin actually falls", "Net profit margin cannot change unless net profit in pounds also changes", "Net profit margin always rises whenever net profit in pounds is unchanged", "Net profit margin depends only on cost of sales, not on revenue at all"]}'::jsonb, '{"answer": 0, "explain": "The card''s example shows net profit staying at £30,000 while revenue doubles, causing NPM to halve from 20% to 10% — margin depends on the relationship between profit and revenue."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:misc:3a41237e', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All wages are variable costs.</p><p><strong>✅ The correct idea:</strong> It depends on how workers are paid. Hourly wages that vary with output are variable. Annual salaries (a fixed payment) are a fixed cost. Examiners specifically do NOT accept ''salaries'' as a variable cost.</p>", "question": "Which statement about wages and salaries does this card confirm is correct?", "options": ["Wages and salaries are both always classed as cost of sales figures", "Hourly wages that vary with output are variable costs, but salaries are fixed", "All forms of staff pay, including salaries, count as variable costs", "All forms of staff pay, including hourly wages, always count as fixed costs"]}'::jsonb, '{"answer": 1, "explain": "The card confirms hourly wages that vary with output are variable costs, while salaries (a fixed payment) are fixed costs — examiners do not accept salaries as variable."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:misc:a8082e00', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> In ARR, you divide total income by the cost of investment.</p><p><strong>✅ The correct idea:</strong> You must first subtract the investment cost from total income to get total PROFIT, then divide by years for average annual profit, THEN divide by cost of investment × 100. Skipping step 1 is one of the most common exam errors.</p>", "question": "What must be done before dividing by the cost of investment in an ARR calculation?", "options": ["Add the cost of investment straight onto the total income figure", "Multiply total income by the cost of investment directly and immediately", "Divide total income by the number of years invested immediately", "Subtract the investment cost from total income to find total profit first"]}'::jsonb, '{"answer": 3, "explain": "The card explains you must first subtract investment cost from income to get total profit, then divide by years, THEN divide by cost of investment — skipping step one is a common error."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:misc:a2515bff', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Gross profit margin and net profit margin measure the same thing.</p><p><strong>✅ The correct idea:</strong> GPM = (Gross Profit ÷ Revenue) × 100 — only deducts cost of sales. NPM = (Net Profit ÷ Revenue) × 100 — deducts ALL expenses too. NPM is always lower and is the more accurate measure.</p>", "question": "What is the key difference between gross profit margin and net profit margin?", "options": ["NPM deducts all expenses too, while GPM only deducts cost of sales", "NPM is always higher than GPM because it excludes cost of sales entirely", "GPM and net profit margin are calculated using exactly the same formula", "GPM deducts all expenses, while NPM only deducts cost of sales figures"]}'::jsonb, '{"answer": 0, "explain": "The card explains GPM only deducts cost of sales, while NPM deducts all expenses too, making NPM always lower and the more accurate overall measure."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:misc:e116e161', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If costs increase, the business must be performing worse.</p><p><strong>✅ The correct idea:</strong> Not necessarily. If revenue increases by MORE than the cost increase, profitability can actually improve. The key is the relationship between revenue and costs — measured by profit margins.</p>", "question": "Why might a business still improve its profitability even if its costs increase?", "options": ["If revenue increases by more than the cost increase, profitability can improve", "Profitability can only ever improve when a business''s total costs actually fall", "Costs increasing always means a business is definitely performing worse", "Rising costs always cause both gross and net profit margins to rise too"]}'::jsonb, '{"answer": 0, "explain": "The card explains that if revenue rises by more than costs increase, profitability can still improve — the key is the relationship between revenue and costs, shown by profit margins."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:misc:310d7a32', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Revenue and profit are interchangeable terms for ''money the business makes''.</p><p><strong>✅ The correct idea:</strong> They are completely different. Revenue is total income from sales. Profit is what is left after ALL costs are paid. In an exam, mixing these up will cost you marks on every finance question.</p>", "question": "Why are ''revenue'' and ''profit'' not interchangeable terms in a business context?", "options": ["Revenue is calculated after costs, while profit is calculated before costs", "Revenue is total income from sales, while profit is what remains after costs", "They both mean exactly the same thing — the total money a business makes", "Profit always refers to a much bigger number than revenue in any business"]}'::jsonb, '{"answer": 1, "explain": "The card stresses revenue is total income from sales, while profit is what remains after ALL costs are paid — mixing these up costs marks on finance questions."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:misc:d910b343', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A business that is ''profitable'' always has a positive cash flow.</p><p><strong>✅ The correct idea:</strong> Profit and cash flow are different. A business can be profitable on paper but still run out of cash (e.g. if customers owe money that hasn''t been paid yet). This is a common real-world business failure.</p>", "question": "Why can a profitable business still fail due to cash flow problems?", "options": ["A profitable business is legally guaranteed to always have enough cash", "Cash flow problems can only ever affect businesses that are making a loss", "A business can be profitable on paper but still run out of cash owed by customers", "Profit and cash flow always rise and fall together at precisely the same rate"]}'::jsonb, '{"answer": 2, "explain": "The card explains profit and cash flow are different — a business can be profitable on paper yet run out of cash if customers haven''t paid what they owe."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:tips:2aa50e07', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'tips', 'mcq', 1, '{"readingTitle": "State / Identify — 1 mark — One Point. Stop. Move On.", "reading": "<p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct point. No explanation, no examples, no paragraphs.</p>\n    <p><strong>The common trap:</strong> Writing too much and contradicting yourself, or naming a variable cost when asked for a fixed cost (or vice versa).</p>\n    <ul>\n    <li><strong>✅ Good (1 mark):</strong> <em>\"Rent\"</em> (in response to ''identify a fixed cost'')</li>\n    <li><strong>❌ Bad (0 marks):</strong> <em>\"Production costs\"</em> — too vague. Always name a specific cost.</li>\n    <li><strong>❌ Bad (0 marks):</strong> <em>\"Salaries\"</em> — in response to ''identify a variable cost''. Examiners specifically do NOT accept salaries as a variable cost.</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning:</strong> The word ''vary'' or ''variable'' cannot be used to define ''variable costs''. A derivative of the keyword appearing in the question gains no marks. Say what they ARE (costs that change with output), not what they''re called.</p>", "question": "Which answer would NOT be accepted if asked to ''identify a variable cost''?", "options": ["Raw materials, since usage increases as more units are made", "Wages, since hourly pay changes directly with the level of output produced", "Packaging, since more units produced requires more packaging used", "Salaries, since examiners specifically do not accept this as a variable cost"]}'::jsonb, '{"answer": 3, "explain": "The card states examiners specifically do NOT accept salaries as a variable cost, since a salary is a fixed annual payment rather than one that changes with output."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:tips:e83b0c00', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — State + Develop: The Two-Step Formula", "reading": "<p>Every 2-mark ''Explain'' question needs two linked steps. State a point, then develop it with a ''because'' or ''this means'' or ''so that''.</p>\n    <p><strong>Formula: Point (K) → Development / So what? (U)</strong></p>\n    <ul>\n    <li><strong>❌ Bad (1 mark only):</strong> <em>\"Variable costs change when output changes.\"</em></li>\n    <li><strong>✅ Good (2 marks):</strong> <em>\"Variable costs change when output changes (K), which means if a business produces more units, it will spend more on raw materials and packaging (U).\"</em></li>\n    </ul>\n    <p>For ''Explain why profit is important'': identify a benefit (K) + explain how that benefit actually works for a business (U).</p>\n    <p><strong>✅ Example:</strong> <em>\"Profit can be reinvested in the business (K) to buy new equipment that increases production capacity and reduces costs in the long run (U).\"</em></p>\n    <p><strong>⚠️ Warning:</strong> Do NOT just write a definition when asked to ''explain why''. Definitions score only 1 mark. Always ask yourself: <em>so what? why does it matter?</em></p>", "question": "What must a 2-mark ''Explain'' answer include, beyond a simple definition?", "options": ["A full list of every possible cost a business could ever incur at all", "A development step showing ''so what'' or ''why it matters'' for the business", "A restatement of the original question using slightly different wording", "A second, completely unrelated definition of a totally different key term"]}'::jsonb, '{"answer": 1, "explain": "The card''s formula is Point (K) then Development (U) — a bare definition scores only 1 mark, so the answer must go on to explain ''so what'' or ''why it matters''."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:tips:9f88e67b', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The U → APP → AN Chain: All Three or Zero", "reading": "<p>A 3-mark Analyse question follows a strict chain. <strong>You cannot score Application or Analysis marks without first scoring Understanding.</strong></p>\n    <p><strong>Step 1 — Understanding (U):</strong> Show you understand the concept. What is it? What does it do?</p>\n    <p><strong>Step 2 — Application (APP):</strong> Link your point DIRECTLY to the business in the case study. Quote or reference specific data from the text. Phrases: <em>\"For ACG...\"</em> / <em>\"As the text states...\"</em> / <em>\"With net profit of £210,000 from £860,000 revenue...\"</em></p>\n    <p><strong>Step 3 — Analysis (AN):</strong> State the impact/effect on the business. Phrases: <em>\"This means...\"</em> / <em>\"As a result...\"</em> / <em>\"This will lead to...\"</em> / <em>\"This could cause...\"</em></p>\n    <p><strong>❌ Bad answer (1 mark):</strong> <em>\"Calculating the net profit margin is useful because it shows how profitable a business is.\"</em></p>\n    <p><strong>✅ Good answer (3 marks):</strong> <em>\"Net profit margin shows the percentage of revenue kept as net profit (U). For ACG, with net profit of £210,000 from £860,000 revenue (APP), this is 24.4%, allowing ACG to compare this year''s efficiency against previous years (AN), alerting them if the margin is falling even as profit in pounds appears to rise.\"</em></p>\n    <p><strong>🚫 No case study reference = maximum 2 marks.</strong> Always name the business and use its specific data.</p>", "question": "What is the maximum mark available if an analyse answer does not reference the case study?", "options": ["1 mark, since understanding alone is always enough for full credit", "3 marks, since analysis can still be scored without any application", "0 marks, since absolutely no marks can be given without application", "2 marks, since application requires naming the business and its data"]}'::jsonb, '{"answer": 3, "explain": "The card states no case study reference caps the answer at 2 marks maximum — you must name the business and use its specific data to access the application mark."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:tips:19670e20', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'tips', 'mcq', 1, '{"readingTitle": "Calculation — 2-3 marks — Always Show Your Workings — Every Step Earns Marks", "reading": "<p>Calculation questions award marks for the process, not just the answer. Even if your final number is wrong, correct working earns marks.</p>\n    <p><strong>Golden Rules:</strong></p>\n    <ul>\n    <li>Write the formula first: <em>NPM = (Net Profit ÷ Revenue) × 100</em></li>\n    <li>Substitute the numbers: <em>(£210,000 ÷ £860,000) × 100</em></li>\n    <li>Write the answer with units: <em>= 24.4%</em></li>\n    <li>Always include the % sign for margin and ARR answers</li>\n    </ul>\n    <p><strong>Most Common Calculation Mistakes:</strong></p>\n    <ul>\n    <li>❌ <strong>ARR:</strong> Dividing total income (not profit) by cost of investment. You MUST subtract the investment cost first.</li>\n    <li>❌ <strong>GPM / NPM:</strong> Using the wrong denominator — always divide by REVENUE, not by cost of sales or gross profit.</li>\n    <li>❌ <strong>Average Revenue:</strong> Using the wrong time period — re-read the question carefully for start and end dates.</li>\n    <li>❌ <strong>Percentage change:</strong> Dividing by the NEW value instead of the ORIGINAL value.</li>\n    </ul>\n    <p><strong>Percentage Change Formula: (Change ÷ Original Value) × 100</strong></p>\n    <p>⚠️ If an answer seems unrealistically large (e.g. £1600m), always re-check whether you accidentally multiplied instead of divided.</p>", "question": "According to this card, what is a common mistake when calculating GPM or NPM?", "options": ["Writing out the formula before substituting in the actual numbers", "Including a percentage sign at the very end of the final answer", "Using the wrong denominator instead of always dividing by revenue", "Showing each step of the calculation instead of just the final answer"]}'::jsonb, '{"answer": 2, "explain": "The card lists using the wrong denominator as a common mistake — GPM and NPM must always be divided by revenue, not by cost of sales or gross profit."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:tips:f473e358', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'tips', 'mcq', 1, '{"readingTitle": "Recommend / Evaluate — 3 marks — Make a Clear Decision — Never Sit on the Fence", "reading": "<p>A recommendation question requires a <strong>clear, committed judgement</strong>. Sitting on the fence scores zero evaluation marks.</p>\n    <p><strong>Three-Part Structure:</strong></p>\n    <ul>\n    <li><strong>Judgement (1 mark):</strong> State your recommendation clearly. <em>\"SP should buy HD Sewing.\"</em></li>\n    <li><strong>Justification (1 mark):</strong> Explain WHY using sound business reasoning.</li>\n    <li><strong>Context (1 mark):</strong> Support with specific data from the table or case study.</li>\n    </ul>\n    <p><strong>✅ Model Response:</strong><br>\n    <em>\"SP should buy Fast Stitch (JUDGEMENT) because Pippa stated she wants to see her investment returned within five years (CONTEXT), and Fast Stitch has a higher ARR of 13.8% compared to HD Sewing''s 11.25% (DATA), meaning it offers a better return on investment and is more likely to achieve Pippa''s goal (JUSTIFICATION).\"</em></p>\n    <p><strong>⚠️ Examiner Warning:</strong> \"It could go either way\" or \"both have advantages\" without a final decision = 0 marks for evaluation. You MUST commit. You can briefly acknowledge the other side, but always return to your chosen recommendation.</p>", "question": "What score does an answer get for evaluation if it doesn''t commit to a decision?", "options": ["Half marks, as long as the overall answer is a reasonable length", "One mark, provided that some numerical data is mentioned somewhere", "Zero evaluation marks, even if both sides are discussed in real detail", "Full marks, since discussing both sides shows a genuinely balanced judgement"]}'::jsonb, '{"answer": 2, "explain": "The card warns that saying ''it could go either way'' without a final decision scores zero evaluation marks — a clear, committed judgement is required."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:tips:1847307b', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'tips', 'mcq', 1, '{"readingTitle": "Profitability Interpretation — 3 marks — Impact on Profitability ≠ Impact on Profit", "reading": "<p>When analysing profitability data, examiners look for the <strong>difference between profit (£ amount) and profitability (the ratio)</strong>. Many students confuse these.</p>\n    <p><strong>To show an impact on PROFITABILITY, the relationship between costs and revenue must change.</strong></p>\n    <p><strong>Three-Step Structure:</strong></p>\n    <ul>\n    <li><strong>Understanding (U):</strong> <em>\"CFM''s gross profit margin rose from 60% in Year 1 to 70% in Year 2.\"</em></li>\n    <li><strong>Application (APP):</strong> <em>\"This means CFM retained 70p of every £1 of revenue after paying for its food supplies in Year 2, compared to 60p in Year 1.\"</em></li>\n    <li><strong>Analysis (AN):</strong> <em>\"This improvement shows CFM is becoming more efficient at generating profit from its sales — the business could use this improved margin to fund the new café from retained profit rather than borrowing.\"</em></li>\n    </ul>\n    <p><strong>❌ Common mistake:</strong> Saying <em>\"the business''s profit will increase\"</em> when asked about profitability. Always discuss the RATIO and what it means for efficiency, not just the pound figure.</p>\n    <p><strong>Sentence starters for AN marks:</strong> <em>\"This means the business is becoming more/less efficient at...\"</em> / <em>\"As a result, the business generates more/less profit per pound of revenue...\"</em></p>", "question": "What mistake do many students make when asked about a change in profitability?", "options": ["They avoid mentioning either profit or profitability in their answer", "They discuss the ratio rather than the pound figure for profit itself", "They discuss the change in profit rather than the change in the ratio", "They correctly discuss both the ratio and the pound figure together"]}'::jsonb, '{"answer": 2, "explain": "The card warns students often say ''profit will increase'' when asked about profitability — the answer must discuss the ratio and what it means for efficiency, not the pound figure."}'::jsonb),
