('business:5-3-revenue-costs-profit-loss:match:fbd02bcb', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Revenue”?", "options": ["Costs that do not change when output changes — e.g. rent, insurance, salaries.", "Costs that change directly with output — e.g. raw materials, packaging, hourly wages.", "Fixed costs plus variable costs (TC = TFC + TVC).", "The income received from sales, calculated as quantity sold × selling price."]}'::jsonb, '{"answer": 3, "explain": "“Revenue” means: The income received from sales, calculated as quantity sold × selling price."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:1805adaf', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fixed Costs”?", "options": ["Costs that change directly with output — e.g. raw materials, packaging, hourly wages.", "Costs that do not change when output changes — e.g. rent, insurance, salaries.", "Fixed costs plus variable costs (TC = TFC + TVC).", "The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product."]}'::jsonb, '{"answer": 1, "explain": "“Fixed Costs” means: Costs that do not change when output changes — e.g. rent, insurance, salaries."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:05a2da08', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Variable Costs”?", "options": ["Fixed costs plus variable costs (TC = TFC + TVC).", "The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product.", "The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising.", "Costs that change directly with output — e.g. raw materials, packaging, hourly wages."]}'::jsonb, '{"answer": 3, "explain": "“Variable Costs” means: Costs that change directly with output — e.g. raw materials, packaging, hourly wages."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:78f9c563', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Total Costs”?", "options": ["The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product.", "Fixed costs plus variable costs (TC = TFC + TVC).", "The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising.", "Revenue minus cost of sales — profit before running costs are deducted."]}'::jsonb, '{"answer": 1, "explain": "“Total Costs” means: Fixed costs plus variable costs (TC = TFC + TVC)."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:8599bf9b', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cost of Sales”?", "options": ["The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising.", "Revenue minus cost of sales — profit before running costs are deducted.", "Gross profit minus expenses — the most accurate measure of overall business performance.", "The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product."]}'::jsonb, '{"answer": 3, "explain": "“Cost of Sales” means: The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:37edbd71', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Expenses”?", "options": ["The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising.", "Revenue minus cost of sales — profit before running costs are deducted.", "Gross profit minus expenses — the most accurate measure of overall business performance.", "When total costs are greater than total revenue."]}'::jsonb, '{"answer": 0, "explain": "“Expenses” means: The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:b61e68f7', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Gross Profit”?", "options": ["Gross profit minus expenses — the most accurate measure of overall business performance.", "When total costs are greater than total revenue.", "(Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling.", "Revenue minus cost of sales — profit before running costs are deducted."]}'::jsonb, '{"answer": 3, "explain": "“Gross Profit” means: Revenue minus cost of sales — profit before running costs are deducted."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:94dda9d5', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Net Profit”?", "options": ["Gross profit minus expenses — the most accurate measure of overall business performance.", "When total costs are greater than total revenue.", "(Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling.", "(Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs."]}'::jsonb, '{"answer": 0, "explain": "“Net Profit” means: Gross profit minus expenses — the most accurate measure of overall business performance."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:b5921e15', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Loss”?", "options": ["(Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling.", "(Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs.", "When total costs are greater than total revenue.", "(Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments."]}'::jsonb, '{"answer": 2, "explain": "“Loss” means: When total costs are greater than total revenue."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:2e36e318', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Gross Profit Margin”?", "options": ["(Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs.", "(Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling.", "(Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments.", "Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue."]}'::jsonb, '{"answer": 1, "explain": "“Gross Profit Margin” means: (Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:ed38b8e9', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Net Profit Margin”?", "options": ["(Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments.", "Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue.", "(Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs.", "The income received from sales, calculated as quantity sold × selling price."]}'::jsonb, '{"answer": 2, "explain": "“Net Profit Margin” means: (Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:1d45d559', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Average Rate of Return”?", "options": ["Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue.", "(Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments.", "The income received from sales, calculated as quantity sold × selling price.", "Costs that do not change when output changes — e.g. rent, insurance, salaries."]}'::jsonb, '{"answer": 1, "explain": "“Average Rate of Return” means: (Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:b3eb9456', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profitability Ratios”?", "options": ["The income received from sales, calculated as quantity sold × selling price.", "Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue.", "Costs that do not change when output changes — e.g. rent, insurance, salaries.", "Costs that change directly with output — e.g. raw materials, packaging, hourly wages."]}'::jsonb, '{"answer": 1, "explain": "“Profitability Ratios” means: Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue."}'::jsonb),
('business:5-4-break-even:exam:f03bff8a', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q1", "question": "A manufacturer that makes and sells more than its break-even quantity will:", "options": ["Have insufficient revenue to cover costs", "Make a profit", "Need to improve its quality control", "Require an overdraft"], "hint": "Think about what happens to profit when total revenue exceeds total costs.", "starter": "The correct answer is B because selling beyond break-even means..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Make a profit</h5><p><strong>Why B is correct:</strong> Once a business sells more units than its break-even output, total revenue exceeds total costs — a profit is made on every additional unit sold.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Incorrect:</strong> Insufficient revenue to cover costs describes what happens BELOW break-even. Above break-even, revenue more than covers all costs.</li><li><strong>C — Incorrect:</strong> Quality control is unrelated to the break-even quantity. Selling above break-even says nothing about product quality.</li><li><strong>D — Incorrect:</strong> An overdraft relates to a cash flow problem, not to selling above the break-even point. A business can be profitable but still have cash flow issues.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:72a78416', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q4", "question": "How many hours of gardening will Amaya need to do to start to make a profit?", "options": ["1,059 hours", "1,385 hours", "2,340 hours", "3,060 hours"], "caseStudy": "Amaya is a gardener. She charges £15 per hour. Her fixed costs are £18,000 per annum. Her variable costs are £2 per hour.", "hint": "Contribution = selling price − variable cost per hour. Break-even = fixed costs ÷ contribution. Remember to round UP your answer.", "starter": "Contribution per hour = £15 − £2 = £13\nBreak-even = £18,000 ÷ £13 = ...\nRound UP to ... hours"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — 1,385 hours</h5><p><strong>Working:</strong></p><ul><li>Contribution = £15 − £2 = £13 per hour</li><li>Break-even = £18,000 ÷ £13 = 1,384.6 → round UP = <strong>1,385 hours</strong></li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (1,059):</strong> Incorrect — results from using the wrong contribution figure, e.g. dividing by £17 (adding price + VC rather than subtracting).</li><li><strong>C (2,340):</strong> Incorrect — results from an error in dividing by the wrong number, possibly using the selling price alone as the denominator in a partial calculation.</li><li><strong>D (3,060):</strong> Incorrect — results from dividing fixed costs only by the variable cost (£18,000 ÷ £2 × something), ignoring the correct contribution formula entirely.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:f4e2b0bd', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q5", "question": "How many one-hour lessons will Kim need to give before making a profit?", "options": ["389 lessons", "467 lessons", "584 lessons", "2,334 lessons"], "caseStudy": "Kim is a driving instructor. Kim charges £30 for a one-hour lesson. Her fixed costs are £14,000 per annum. The variable cost for a one-hour lesson is £6.", "hint": "Contribution = price per lesson − variable cost. Break-even = fixed costs ÷ contribution. Remember to round UP.", "starter": "Contribution per lesson = £30 − £6 = £24\nBreak-even = £14,000 ÷ £24 = ...\nRound UP to ... lessons"}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 584 lessons</h5><p><strong>Working:</strong></p><ul><li>Contribution = £30 − £6 = £24 per lesson</li><li>Break-even = £14,000 ÷ £24 = 583.3 → round UP = <strong>584 lessons</strong></li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (389):</strong> Incorrect — results from using an incorrect contribution figure.</li><li><strong>B (467):</strong> Incorrect — results from dividing by the wrong number in the formula.</li><li><strong>D (2,334):</strong> Incorrect — results from dividing fixed costs by the variable cost only (£14,000 ÷ £6 = 2,333.3), completely ignoring the selling price in the contribution calculation.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:0e542abb', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q8", "question": "If Andrea paints and sells 50 portraits a year, total costs are estimated to be:", "options": ["£1,075 per year", "£4,750 per year", "£12,075 per year", "£15,750 per year"], "caseStudy": "Andrea specialises in painting portraits. She estimates that:\n• variable costs for labour are £52 per portrait\n• variable costs for materials are £23 per portrait\n• fixed costs are £1,000 per month", "hint": "Convert monthly fixed costs to annual first (× 12). Then calculate total variable costs (VC per portrait × 50). Finally, add fixed and variable costs together.", "starter": "Annual fixed costs = £1,000 × 12 = £12,000\nVC per portrait = £52 + £23 = £75\nTotal VC = £75 × 50 = £3,750\nTotal costs = £12,000 + £3,750 = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £15,750 per year</h5><p><strong>Working:</strong></p><ul><li>Annual fixed costs = £1,000 × 12 = £12,000</li><li>Variable cost per portrait = £52 + £23 = £75</li><li>Total variable costs = £75 × 50 = £3,750</li><li>Total costs = £12,000 + £3,750 = <strong>£15,750</strong></li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (£1,075):</strong> Incorrect — results from simply adding £52 + £23 + £1,000 without multiplying by 50 portraits or converting monthly to annual FC. Completely ignores the quantities involved.</li><li><strong>B (£4,750):</strong> Incorrect — results from using the monthly fixed cost (£1,000) instead of the annual figure (£12,000), giving £3,750 + £1,000 = £4,750.</li><li><strong>C (£12,075):</strong> Incorrect — likely used only one variable cost component (e.g. just £52 or £23) rather than adding both together, then added the annual FC of £12,000.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:98af4d76', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q9", "question": "At break-even a firm''s total revenue equals its:", "options": ["Fixed costs only", "Gross profit", "Net profit", "Total costs"], "hint": "At break-even, the business makes no profit and no loss. What does this tell you about the relationship between revenue and costs?", "starter": "At break-even, TR = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Total costs</h5><p>At break-even, total revenue equals total costs (TR = TC). The business makes neither a profit nor a loss.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Fixed costs only:</strong> Total revenue must cover BOTH fixed AND variable costs to break even. Fixed costs alone understates the total costs the business must cover.</li><li><strong>B — Gross profit:</strong> Gross profit = revenue − cost of sales. At break-even, net profit is zero, but gross profit may still exist. Gross profit is not the same as total costs.</li><li><strong>C — Net profit:</strong> If TR equalled net profit, there would be no costs at all — this is clearly impossible for any real business.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:0322e36e', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which of the following is a limitation of break-even analysis?", "options": ["It cannot be used to estimate the profit a business is likely to make", "It cannot factor in seasonal pricing and price discounts", "It cannot show how much a business needs to sell to cover its costs", "It cannot show the level of profit or loss at a range of outputs"], "hint": "Think about what break-even CANNOT do. Eliminate options A, C, and D by checking whether break-even CAN actually do those things.", "starter": "The correct answer is B because break-even analysis assumes..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — It cannot factor in seasonal pricing and price discounts</h5><p>Break-even assumes a single, fixed selling price throughout. It cannot account for price changes such as seasonal discounts, promotional pricing, or variable pricing strategies — all of which affect actual revenue differently at different points in time.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Incorrect:</strong> Break-even CAN be used to estimate profit at different output levels — by comparing TR with TC at any point on the graph or table.</li><li><strong>C — Incorrect:</strong> Showing how much a business must sell to cover its costs IS the core purpose and main strength of break-even analysis.</li><li><strong>D — Incorrect:</strong> By comparing TR and TC at various outputs (on a graph or in a table), break-even CAN show the level of profit or loss across a full range of outputs.</li></ul><p><strong>Examiner''s Comment:</strong> Many candidates chose A because they saw the word \"estimate\" and assumed it must be a limitation. This is a common trap — always read all four options carefully before selecting. Each MCQ is worth 1 mark and deserves at least a minute of careful thought.</p></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:mcq:328ae7f4', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "What is the break-even quantity?", "options": ["The output level at which a business maximises its profit", "The output level at which total revenue equals total costs", "The output level at which fixed costs equal variable costs", "The output level at which a business earns its highest revenue"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Break-even is the point where total revenue exactly equals total costs, so the business makes neither a profit nor a loss."}'::jsonb),
('business:5-4-break-even:mcq:f4f8b70a', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "A manufacturer that makes and sells MORE than its break-even quantity will:", "options": ["Have insufficient revenue to cover costs", "Make a profit", "Need to improve its quality control", "Require an overdraft"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Once a business sells beyond its break-even output, total revenue exceeds total costs, resulting in a profit. Options A and D are what happens BELOW break-even. Option C is unrelated to break-even."}'::jsonb),
('business:5-4-break-even:mcq:0a3f8962', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "At break-even, a firm''s total revenue equals its:", "options": ["Fixed costs only", "Gross profit", "Net profit", "Total costs"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. At break-even, TR = TC. The business covers ALL costs (fixed AND variable), meaning there is zero profit and zero loss."}'::jsonb),
('business:5-4-break-even:mcq:2fde6fe0', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Amaya is a gardener. She charges £15 per hour. Her fixed costs are £18,000 per annum. Her variable costs are £2 per hour. How many hours does Amaya need to work to START making a profit?", "options": ["1,059 hours", "1,385 hours", "2,340 hours", "3,060 hours"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — 1,385 hours. Contribution = £15 − £2 = £13. Break-even = £18,000 ÷ £13 = 1,384.6 → round UP to 1,385 hours. Always round up because you cannot break even on a fraction of a unit."}'::jsonb),
('business:5-4-break-even:mcq:f16edf6c', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Kim is a driving instructor charging £30 per lesson. Fixed costs are £14,000 per year. Variable costs are £6 per lesson. How many lessons must Kim give before making a profit?", "options": ["389 lessons", "467 lessons", "584 lessons", "2,334 lessons"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — 584 lessons. Contribution = £30 − £6 = £24. Break-even = £14,000 ÷ £24 = 583.3 → round UP to 584. Option D results from dividing by variable cost only (÷ £6), ignoring the selling price."}'::jsonb),
('business:5-4-break-even:mcq:0322e36e', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Which of the following is a limitation of break-even analysis?", "options": ["It cannot be used to estimate the profit a business is likely to make", "It cannot factor in seasonal pricing and price discounts", "It cannot show how much a business needs to sell to cover its costs", "It cannot show the level of profit or loss at a range of outputs"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Break-even assumes a single fixed price. It cannot account for seasonal pricing, promotional discounts, or variable pricing — all of which affect actual revenue. Options A, C, and D are all things break-even CAN do."}'::jsonb),
('business:5-4-break-even:mcq:fad7487c', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "A business has fixed costs of £20,000, a selling price of £50, and variable costs of £30 per unit. What is its break-even output?", "options": ["400 units", "667 units", "1,000 units", "1,500 units"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — 1,000 units. Contribution = £50 − £30 = £20. Break-even = £20,000 ÷ £20 = 1,000 units."}'::jsonb),
('business:5-4-break-even:mcq:7d606c4b', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "A business''s actual output is 5,000 units and its break-even output is 3,500 units. What is the margin of safety?", "options": ["1,500 units", "3,500 units", "5,000 units", "8,500 units"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — 1,500 units. Margin of safety = actual sales − break-even sales = 5,000 − 3,500 = 1,500 units."}'::jsonb),
('business:5-4-break-even:mcq:93a177f6', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Carlton Press Ltd has fixed costs of £30,000, variable costs of £2 per booklet, and sells each booklet at £5. What is the break-even output?", "options": ["5,000 booklets", "10,000 booklets", "15,000 booklets", "20,000 booklets"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — 10,000 booklets. Contribution = £5 − £2 = £3. Break-even = £30,000 ÷ £3 = 10,000 booklets."}'::jsonb),
('business:5-4-break-even:mcq:d219560c', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Which of these may cause a break-even forecast to turn out to be incorrect?", "options": ["The number of competitors in the market remains the same", "The business sells all its goods at its planned price", "The cost of importing raw materials increases", "Workers accept the planned rise in wages"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. If raw material costs increase, variable costs rise unexpectedly — making the original break-even forecast inaccurate. Options A, B, and D all describe scenarios where things go exactly as planned, so the forecast would remain valid."}'::jsonb),
('business:5-4-break-even:mcq:194f9c33', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "A business will make a LOSS if:", "options": ["Its revenues are greater than its costs", "It uses its revenues to pay off all its debts", "It sells less than its break-even output", "It has to take out an overdraft"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A business makes a loss when it sells fewer units than its break-even output — meaning total costs exceed total revenue. An overdraft is a cash flow issue; it does not automatically mean the business is making a loss."}'::jsonb),
('business:5-4-break-even:mcq:11b684ec', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "If Carlton Press Ltd (break-even = 10,000) sells 20,000 books, what is its margin of safety?", "options": ["5,000 booklets", "10,000 booklets", "15,000 booklets", "20,000 booklets"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — 10,000 booklets. Margin of safety = actual sales − break-even output = 20,000 − 10,000 = 10,000 booklets."}'::jsonb),
('business:5-4-break-even:mcq:dc4a8a93', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "If a business''s fixed costs INCREASE, what happens to its break-even output?", "options": ["It decreases because there are more costs to spread", "It increases because more units must be sold to cover the higher costs", "It stays the same because variable costs are unchanged", "It decreases because contribution per unit rises"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Break-even = FC ÷ contribution. If fixed costs rise (numerator increases) while contribution stays the same, the result is a higher break-even output — the business must sell more units to cover all its costs."}'::jsonb),
('business:5-4-break-even:mcq:0a301562', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Andrea paints portraits. Labour VC = £52, materials VC = £23 per portrait, fixed costs = £1,000 per month. If she paints 50 portraits per year, total annual costs are:", "options": ["£1,075 per year", "£4,750 per year", "£12,075 per year", "£15,750 per year"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — £15,750. Annual FC = £1,000 × 12 = £12,000. VC per portrait = £52 + £23 = £75. TVC = £75 × 50 = £3,750. Total costs = £12,000 + £3,750 = £15,750. Many students forget to convert monthly FC to annual."}'::jsonb),
('business:5-4-break-even:tf:b5f0811b', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Break-even is the point at which total revenue equals total costs."}'::jsonb, '{"answer": true, "explain": "TRUE. At break-even, TR = TC exactly. The business covers all its costs but makes neither a profit nor a loss. This is the core definition."}'::jsonb),
('business:5-4-break-even:tf:14c6ccca', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Break-even output is measured in pounds (£), not units."}'::jsonb, '{"answer": false, "explain": "FALSE. Break-even output is always measured in UNITS (e.g., 12,500 toys or 30 cakes). Writing a £ sign instead of units will cost you a mark in the exam."}'::jsonb),
('business:5-4-break-even:tf:9eddbc05', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "If a business sells more than its break-even output, it will make a profit."}'::jsonb, '{"answer": true, "explain": "TRUE. Once output exceeds break-even, every additional unit sold generates profit — because total revenue now exceeds total costs."}'::jsonb),
('business:5-4-break-even:tf:8de7fb35', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Fixed costs change depending on the level of output produced."}'::jsonb, '{"answer": false, "explain": "FALSE. Fixed costs remain the same regardless of output. Rent is the same whether a business produces 100 or 10,000 units. It is variable costs that change with output."}'::jsonb),
('business:5-4-break-even:tf:e7f6cefe', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "An increase in selling price will cause the break-even output to decrease."}'::jsonb, '{"answer": true, "explain": "TRUE. A higher price increases the contribution per unit. Since break-even = FC ÷ contribution, a larger contribution means fewer units need to be sold to cover fixed costs."}'::jsonb),
('business:5-4-break-even:tf:a45d3df6', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "An increase in variable costs per unit will cause the break-even output to decrease."}'::jsonb, '{"answer": false, "explain": "FALSE. If variable costs increase, contribution per unit falls (price − VC is smaller). A lower contribution means MORE units must be sold to cover fixed costs — so break-even output INCREASES."}'::jsonb),
('business:5-4-break-even:tf:3cff9d80', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "The margin of safety is calculated by subtracting break-even sales from actual sales."}'::jsonb, '{"answer": true, "explain": "TRUE. Margin of safety = actual sales − break-even sales. It shows how far sales can fall before the business starts making a loss."}'::jsonb),
('business:5-4-break-even:tf:4d605968', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Break-even analysis gives perfectly accurate predictions because it is based on mathematical calculations."}'::jsonb, '{"answer": false, "explain": "FALSE. Break-even uses estimated figures for future costs and revenues — it is a forecast, not a certainty. Actual results may differ due to competitors, price changes, or rising raw material costs."}'::jsonb),
('business:5-4-break-even:tf:0a79c038', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Break-even analysis is most accurate for businesses that sell a wide variety of different products."}'::jsonb, '{"answer": false, "explain": "FALSE. Break-even is most straightforward for single-product businesses. Multi-product businesses have different costs and prices for each product, making break-even analysis complex and much less reliable."}'::jsonb),
('business:5-4-break-even:tf:29a51021', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "A break-even forecast can help a business secure a bank loan."}'::jsonb, '{"answer": true, "explain": "TRUE. Banks often ask to see a break-even forecast as part of a business plan. It demonstrates the owner has planned carefully and understood their finances, reassuring the bank that the loan is less risky."}'::jsonb),
('business:5-4-break-even:tf:6eaddf2b', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "On a break-even graph, the Total Revenue line starts at zero when output is zero."}'::jsonb, '{"answer": true, "explain": "TRUE. If a business sells zero units, it earns zero revenue. The Total Revenue line always begins at the origin (0, 0) and rises diagonally as units are sold."}'::jsonb),
('business:5-4-break-even:tf:6186c79e', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "On a break-even graph, the Fixed Costs line rises diagonally from left to right."}'::jsonb, '{"answer": false, "explain": "FALSE. The Fixed Costs line is horizontal — it stays flat at the same level regardless of output. It is the Total Costs and Total Revenue lines that are diagonal."}'::jsonb),
('business:5-4-break-even:learn:1052c3a8', 'business', 'business:5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>Break-even analysis is a financial tool that helps businesses calculate the minimum number of units they must sell to cover all costs — making neither a profit nor a loss.</p>\n    <ul>\n      <li><strong>Break-even quantity:</strong> The amount a business must sell to earn enough revenue to just cover its costs so that it does not make a profit or a loss.</li>\n      <li><strong>Contribution per unit:</strong> Selling price minus variable cost per unit. Each unit sold \"contributes\" towards covering fixed costs before profit can be made.</li>\n      <li><strong>Total Revenue (TR):</strong> Selling price × quantity sold.</li>\n      <li><strong>Fixed Costs:</strong> Costs that do not change depending on output (e.g., rent, insurance, loan repayments).</li>\n      <li><strong>Variable Costs:</strong> Costs that change depending on the level of output (e.g., raw materials, packaging, direct labour).</li>\n      <li><strong>Total Costs:</strong> Total fixed costs + total variable costs.</li>\n      <li><strong>Margin of Safety:</strong> Actual sales − break-even sales. The amount by which a business''s actual output is greater than its break-even level of output.</li>\n      <li><strong>Break-even forecast:</strong> A prediction about the break-even quantity based on estimates of future sales revenues and costs.</li>\n      <li><strong>Profit:</strong> Total revenue − total costs (when TR > TC).</li>\n      <li><strong>Loss:</strong> When total costs exceed total revenue (TC > TR) — this occurs when output is below the break-even point.</li>\n    </ul>", "question": "According to the key definitions, what is ''contribution per unit''?", "options": ["Total revenue minus total costs of the business", "Selling price minus variable cost per unit", "Selling price minus total fixed costs of the business", "Fixed costs divided by the total quantity sold"]}'::jsonb, '{"answer": 1, "explain": "The card defines contribution per unit as selling price minus variable cost per unit — the amount each unit contributes towards covering fixed costs."}'::jsonb),
('business:5-4-break-even:learn:181aa6be', 'business', 'business:5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Calculating the Break-Even Quantity", "reading": "<p>There is one formula you must know for the OCR GCSE exam. Break-even is <strong>always recorded in units</strong>, never in pounds (£).</p>\n    <div class=\"formula-box\">\n      <strong>Break-Even Output =</strong> Total Fixed Costs ÷ Contribution per Unit<br><br>\n      <strong>Contribution per Unit =</strong> Selling Price − Variable Cost per Unit\n    </div>\n    <p><strong>Worked Example:</strong> A toy manufacturer has fixed costs of £50,000, sells toys at £6 each, and variable costs of £2 per toy.</p>\n    <ul>\n      <li>Contribution = £6 − £2 = <strong>£4 per unit</strong></li>\n      <li>Break-even = £50,000 ÷ £4 = <strong>12,500 units</strong></li>\n    </ul>\n    <p><strong>⚠️ Key Rules:</strong></p>\n    <ul>\n      <li><strong>Always round UP</strong> if your answer is a decimal — you cannot break even on a fraction of a unit. For example, 583.3 rounds up to 584.</li>\n      <li><strong>Always show your working</strong> — even if the final answer is wrong, you can earn method marks for each correct step.</li>\n      <li><strong>Watch for time period traps</strong> — if costs are given weekly but the question asks for a daily break-even, divide fixed costs by 7 first.</li>\n    </ul>", "question": "According to this card, how should the break-even output always be recorded?", "options": ["In units, always rounded down if the answer is a decimal", "In pounds, always rounded down if the answer is a decimal", "In units, always rounded up if the answer is a decimal", "In pounds, always rounded up if the answer is a decimal"]}'::jsonb, '{"answer": 2, "explain": "The card states break-even is always recorded in units and rounded UP if the answer is a decimal, since a business cannot break even on a fraction of a unit."}'::jsonb),
('business:5-4-break-even:learn:56a5f32f', 'business', 'business:5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "The Break-Even Graph", "reading": "<p>Break-even can be shown visually using a line graph. You may be asked to <strong>read and interpret</strong> a break-even graph in the exam.</p>\n    <ul>\n      <li><strong>Horizontal axis (x-axis):</strong> Output / Units sold</li>\n      <li><strong>Vertical axis (y-axis):</strong> Costs and Revenue (£)</li>\n      <li><strong>Fixed Costs line:</strong> A <em>horizontal</em> straight line — costs stay the same at all levels of output</li>\n      <li><strong>Total Costs line:</strong> Starts at the fixed cost level, then rises diagonally as output increases (adding variable costs)</li>\n      <li><strong>Total Revenue line:</strong> Starts at zero (no sales = no revenue), rises diagonally as output increases</li>\n      <li><strong>Break-even point:</strong> Where the Total Revenue line crosses the Total Costs line (TR = TC)</li>\n      <li><strong>Loss area:</strong> To the <em>left</em> of the break-even point — TC > TR, so the business makes a loss</li>\n      <li><strong>Profit area:</strong> To the <em>right</em> of the break-even point — TR > TC, so the business makes a profit</li>\n    </ul>\n    <p>The <strong>Margin of Safety</strong> is shown as the horizontal distance between actual output and the break-even point. A larger margin of safety means the business has more protection against a fall in sales.</p>", "question": "According to this card, what does the area to the left of the break-even point represent?", "options": ["The loss area, where total costs exceed total revenue", "The fixed cost area, where output has no effect on revenue", "The profit area, where total revenue exceeds total costs", "The margin of safety, showing spare capacity above the target"]}'::jsonb, '{"answer": 0, "explain": "The card explains the loss area lies to the left of the break-even point, where TC > TR; the profit area lies to the right, where TR > TC."}'::jsonb),
('business:5-4-break-even:learn:4b639d43', 'business', 'business:5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Benefits of Break-Even Analysis", "reading": "<p>Break-even analysis is a powerful planning tool with several key benefits for businesses:</p>\n    <ul>\n      <li><strong>Planning sales targets:</strong> It shows exactly how many units must be sold to make a profit, giving the business a specific, measurable target to aim for.</li>\n      <li><strong>Securing a bank loan:</strong> Banks often ask to see a break-even forecast as part of a business plan. It demonstrates that the owner has planned carefully, reducing the risk for the bank and making them more willing to lend.</li>\n      <li><strong>Pricing and cost decisions:</strong> If the break-even output is too high to be realistic, the business can consider raising its price or cutting variable/fixed costs to lower the break-even point.</li>\n      <li><strong>Estimating expected profit:</strong> Once break-even is known, the business can forecast how much profit it would make at different levels of output.</li>\n      <li><strong>Assessing the margin of safety:</strong> The business can evaluate how far sales can fall before it starts making a loss, helping it plan for economic uncertainty.</li>\n    </ul>", "question": "According to this card, why might a bank be more willing to lend to a business?", "options": ["A break-even forecast proves the business will never face any real competitors at all", "Break-even analysis removes the business''s need to ever repay any interest", "A break-even forecast shows the owner has planned carefully, reducing the bank''s risk", "Break-even analysis guarantees that the business will always be profitable"]}'::jsonb, '{"answer": 2, "explain": "The card lists securing a bank loan as a benefit, since a break-even forecast demonstrates careful planning and reduces the perceived risk for the bank."}'::jsonb),
('business:5-4-break-even:learn:f6af63ff', 'business', 'business:5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Limitations of Break-Even Analysis", "reading": "<p>Despite its usefulness, break-even analysis has several important limitations that businesses must be aware of:</p>\n    <ul>\n      <li><strong>It is only a prediction:</strong> All figures used are estimates of future costs and revenues. Actual results may differ significantly from the forecast.</li>\n      <li><strong>Competitors may change:</strong> If a new competitor enters the market, the business may have to lower its price to maintain sales. This reduces contribution per unit and raises the break-even output — making the original forecast inaccurate.</li>\n      <li><strong>Variable costs may change:</strong> If the cost of raw materials rises or falls unexpectedly, the variable cost per unit changes, altering the contribution and therefore the break-even point.</li>\n      <li><strong>Difficult for multi-product businesses:</strong> Calculating break-even is straightforward for a single-product business but becomes complex and less reliable when a firm sells many different products at different prices and costs.</li>\n      <li><strong>Promotional pricing is ignored:</strong> A business may offer discounts at launch, meaning actual revenue is less than the planned price — raising the real break-even output.</li>\n      <li><strong>Price increases may not raise revenue:</strong> If a price rise leads to a large fall in demand, total revenue could actually decrease — meaning the assumed revenue line on the graph would be inaccurate.</li>\n    </ul>", "question": "According to this card, why can a new competitor make a break-even forecast inaccurate?", "options": ["A new competitor always forces the business to stop selling its products internationally", "A new competitor guarantees that the business''s break-even output will fall", "A new competitor automatically increases the business''s total fixed costs", "The business may have to lower its price, reducing contribution and raising break-even"]}'::jsonb, '{"answer": 3, "explain": "The card explains a new competitor may force a price cut, reducing contribution per unit and raising the real break-even output above the original forecast."}'::jsonb),
('business:5-4-break-even:learn:56eb8162', 'business', 'business:5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Advantages vs Disadvantages of Break-Even Analysis", "reading": "<div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Clear sales target:</strong> Shows exactly how many units must be sold to cover all costs and move into profit — giving management a specific goal to plan around.</div>\n    <div class=\"pro-item\"><strong>Supports bank loan applications:</strong> A bank manager is more likely to lend money if the business can present a break-even forecast as part of a well-prepared business plan.</div>\n    <div class=\"pro-item\"><strong>Informs pricing and cost decisions:</strong> If the break-even output is too high, the business knows it must either raise its price or reduce its costs to make profitability realistic.</div>\n    <div class=\"pro-item\"><strong>Forecasts profit at different outputs:</strong> Allows the business to estimate how much profit it could make at various sales levels, aiding strategic planning.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Based on estimates only:</strong> All revenue and cost figures are predictions. If prices or costs change unexpectedly, the entire forecast becomes inaccurate.</div>\n    <div class=\"con-item\"><strong>Ignores competition:</strong> New competitors entering the market may force price cuts, reducing contribution per unit and pushing the real break-even output above what was forecast.</div>\n    <div class=\"con-item\"><strong>Variable costs can change:</strong> Raw material price increases raise the variable cost per unit, shrinking the contribution and raising the break-even output beyond the original calculation.</div>\n    <div class=\"con-item\"><strong>Not suitable for multi-product businesses:</strong> Firms selling several products with different costs and prices find break-even analysis complex and unreliable as a guide to overall performance.</div>\n    </div>\n    </div>", "question": "According to this card, why is break-even analysis less reliable for multi-product businesses?", "options": ["Break-even analysis can only ever be calculated using a single fixed cost", "Multi-product businesses are legally banned from using break-even analysis at all", "Calculating break-even becomes complex when products have different prices and costs", "Multi-product businesses never have any variable costs to include at all"]}'::jsonb, '{"answer": 2, "explain": "The card lists multi-product businesses as a limitation, since calculating break-even is complex and less reliable when products have different prices and costs."}'::jsonb),
('business:5-4-break-even:learn:3d90d47c', 'business', 'business:5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "How Changes Affect the Break-Even Point", "reading": "<p>A key exam skill is predicting what happens to the break-even output when variables change. Use the formula to reason through each scenario logically:</p>\n    <ul>\n      <li><strong>Selling price increases &rarr;</strong> Contribution per unit rises &rarr; Break-even output <strong>decreases</strong> (fewer units needed).</li>\n      <li><strong>Selling price decreases &rarr;</strong> Contribution per unit falls &rarr; Break-even output <strong>increases</strong> (more units needed).</li>\n      <li><strong>Fixed costs increase &rarr;</strong> More costs to cover &rarr; Break-even output <strong>increases</strong>.</li>\n      <li><strong>Fixed costs decrease &rarr;</strong> Fewer costs to cover &rarr; Break-even output <strong>decreases</strong>.</li>\n      <li><strong>Variable cost per unit increases &rarr;</strong> Contribution per unit falls &rarr; Break-even output <strong>increases</strong>.</li>\n      <li><strong>Variable cost per unit decreases &rarr;</strong> Contribution per unit rises &rarr; Break-even output <strong>decreases</strong>.</li>\n    </ul>\n    <p>On a break-even graph: a <strong>price increase</strong> is shown as a steeper Total Revenue line (pivoting upward). A <strong>rise in variable costs</strong> is shown as a steeper Total Costs line (pivoting upward from the fixed cost level).</p>", "question": "According to this card, what happens to the break-even output if fixed costs increase?", "options": ["It stays exactly the same, since fixed costs do not affect break-even", "It decreases, since higher fixed costs raise contribution per unit", "It increases, since more costs must be covered by contribution", "It decreases, since fewer units are then needed to cover costs"]}'::jsonb, '{"answer": 2, "explain": "The card explains that when fixed costs increase, there are more costs to cover, so the break-even output increases — the opposite happens when fixed costs fall."}'::jsonb),
('business:5-4-break-even:learn:d568b52f', 'business', 'business:5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Lord Digby Jones & Hereford Furniture", "reading": "<div class=\"case-study-box\">\n    <h4>Case Study: Hereford Furniture</h4>\n    <p>Lord Digby Jones, a respected businessman, appeared on a BBC TV programme called <em>The New Trouble Shooter</em>. He visited Hereford Furniture, a family-owned business run by Mike Muxworthy and his daughter Kate. At the time of his visit, the business was making a loss of £80,000 and the jobs of 40 workers were at risk.</p>\n    <p>Lord Jones <strong>heavily criticised the owners for not completing break-even forecasts</strong>, calling them \"essential for good business planning.\" Without knowing their break-even output, the owners had no clear sales target and no way of knowing whether their pricing was sufficient to cover costs.</p>\n    <p><strong>The Takeaway:</strong> Even established businesses must regularly calculate break-even. Without it, managers are effectively \"flying blind\" — unable to make informed decisions about price, costs, or how much to produce. Lord Jones'' intervention helped the business develop a clear financial plan to return to profitability.</p>\n    </div>", "question": "According to the Hereford Furniture case study, what did Lord Digby Jones criticise the owners for?", "options": ["Employing far too many staff relative to their level of output", "Charging their customers far too little for their furniture products", "Not completing break-even forecasts as part of their business planning", "Refusing to apply for any external sources of finance at all"]}'::jsonb, '{"answer": 2, "explain": "The card explains Lord Jones criticised Hereford Furniture for not completing break-even forecasts, calling them essential for good business planning."}'::jsonb),
('business:5-4-break-even:learn:3956385b', 'business', 'business:5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Samantha Dixon — Cake Decorating", "reading": "<div class=\"case-study-box\">\n    <h4>Case Study: Samantha Dixon — Wedding Cake Business</h4>\n    <p>Samantha Dixon is starting up a cake decorating business. In her area there are already two other cake decorating businesses. She estimates she can sell wedding cakes at £300 each — slightly less than her competitors. Variable costs per cake are £180. Her fixed costs are £3,600 per year.</p>\n    <p><strong>Break-Even Calculation:</strong></p>\n    <ul>\n      <li>Contribution = £300 − £180 = £120 per cake</li>\n      <li>Break-even = £3,600 ÷ £120 = <strong>30 cakes per year</strong></li>\n    </ul>\n    <p><strong>What this means for Samantha:</strong></p>\n    <ul>\n      <li>She must sell at least 30 cakes before making any profit.</li>\n      <li>If she expects to sell 35 cakes, her margin of safety is 35 − 30 = 5 cakes.</li>\n      <li>She can show this forecast to a bank manager to support a loan application, demonstrating she has a clear financial plan.</li>\n    </ul>\n    <p><strong>Key Limitation:</strong> There are already 2 competitors. If they lower their prices below £300, Samantha may have to follow — reducing contribution per cake and pushing her break-even output above 30, making the forecast inaccurate.</p>\n    </div>", "question": "In the Samantha Dixon case study, what is her margin of safety if she sells 35 cakes?", "options": ["300 cakes, based on her selling price per cake in pounds", "35 cakes, since none of her cakes have covered any costs yet", "180 cakes, based on her variable cost per cake in pounds", "5 cakes, since her break-even output is 30 cakes per year"]}'::jsonb, '{"answer": 3, "explain": "The card calculates Samantha''s margin of safety as actual sales (35) minus break-even sales (30), giving a margin of safety of 5 cakes."}'::jsonb),
('business:5-4-break-even:misc:0a59752a', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write the break-even output in pounds, e.g. ''£12,500'' or ''£30''.</p><p><strong>✅ The correct idea:</strong> Break-even output must always be written in UNITS (e.g., ''12,500 units'' or ''30 cakes''). Writing a £ sign loses you a mark — the examiner is strict on this.</p>", "question": "In what unit must the break-even output always be recorded?", "options": ["In pounds, such as ''£12,500'' or ''£30''", "In percentages, such as ''12,500%'' or ''30%''", "In hours, such as ''12,500 hours'' or ''30 hours''", "In units, such as ''12,500 units'' or ''30 cakes''"]}'::jsonb, '{"answer": 3, "explain": "The card explains break-even output must always be written in units — writing a £ sign loses a mark, as examiners are strict on this."}'::jsonb),
('business:5-4-break-even:misc:eb45bcaf', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think ''break-even'' means the business is doing well or making a profit.</p><p><strong>✅ The correct idea:</strong> At break-even, the business makes NEITHER a profit NOR a loss. Total revenue exactly equals total costs — there is no money left over. It is the minimum acceptable level of sales.</p>", "question": "What does reaching the break-even point actually tell us about a business?", "options": ["It makes neither a profit nor a loss — revenue exactly equals total costs", "It has definitely covered its costs and is now growing quickly", "It is making a healthy profit and performing very well overall", "It has failed completely and will need to close down within the next year"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the misconception that break-even means doing well — at break-even, revenue exactly equals total costs and there is no money left over."}'::jsonb),
('business:5-4-break-even:misc:1b0abf9b', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students use total costs (not fixed costs) in the break-even formula: ''TC ÷ contribution''.</p><p><strong>✅ The correct idea:</strong> The formula uses FIXED COSTS only: FC ÷ contribution. Variable costs are already built into the contribution figure (price − VC), so using total costs would count variable costs twice.</p>", "question": "Which figure is used in the break-even formula: fixed costs or total costs?", "options": ["Total revenue only, since costs do not appear in the formula at all", "Variable costs only, since fixed costs are irrelevant to break-even", "Total costs only, since fixed costs alone would understate the final answer", "Fixed costs only, since variable costs are already built into contribution"]}'::jsonb, '{"answer": 3, "explain": "The card explains the formula uses fixed costs only, since variable costs are already accounted for within the contribution figure — using total costs would double-count them."}'::jsonb),
('business:5-4-break-even:misc:ab0f8899', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students round DOWN when the break-even gives a decimal (e.g., 583.3 becomes 583).</p><p><strong>✅ The correct idea:</strong> Always round UP. At 583 units the business has NOT yet covered all fixed costs — it needs to sell at least 584 to actually break even.</p>", "question": "How should a decimal break-even answer, such as 583.3, be rounded?", "options": ["Rounded to the nearest 10, to 580, for a simpler final answer", "Left as a decimal, since break-even units may include a fraction", "Always rounded up, to 584, since 583 would not cover all fixed costs", "Always rounded down, to 583, to keep the final answer as low as possible"]}'::jsonb, '{"answer": 2, "explain": "The card explains you must always round UP, since at 583 units the business has not yet covered all its fixed costs and would still be making a loss."}'::jsonb),
('business:5-4-break-even:misc:35e7e2d6', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students say break-even analysis is perfectly accurate and reliable because it uses maths.</p><p><strong>✅ The correct idea:</strong> Break-even is a PREDICTION based on estimated figures. Actual costs and revenues may differ significantly — competitors, price changes, or rising material costs can all make the forecast inaccurate.</p>", "question": "Why is break-even analysis not considered perfectly accurate and reliable?", "options": ["It removes the need for a business to consider its competitors at all", "It uses maths, so the result is always guaranteed to be completely correct", "It is a prediction based on estimated figures that may turn out to be wrong", "It only ever uses figures that have already actually happened in the past"]}'::jsonb, '{"answer": 2, "explain": "The card explains break-even is a prediction based on estimated figures — actual costs and revenues may differ significantly due to competitors or rising costs."}'::jsonb),
('business:5-4-break-even:misc:55d6bd21', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When asked to ''analyse a benefit of break-even'', students simply describe what break-even is.</p><p><strong>✅ The correct idea:</strong> The examiner wants U + APP + AN. State the benefit (U), apply it to the specific business in the case study (APP), and explain the impact on THAT business (AN). Describing the concept of break-even without any analysis or application scores zero.</p>", "question": "What must a full-mark ''analyse a benefit of break-even'' answer include, beyond a description?", "options": ["A complete list of every possible benefit of break-even analysis", "Only a general description of what break-even means as a concept", "A definition of profit rather than a definition of break-even itself", "Application to the specific business plus analysis of the impact on it"]}'::jsonb, '{"answer": 3, "explain": "The card explains the examiner wants U + APP + AN — describing the concept of break-even alone, without application or analysis, scores zero."}'::jsonb),
('business:5-4-break-even:misc:67bb625b', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students say ''it shows how many a business needs to sell to break-even'' as their Understanding mark.</p><p><strong>✅ The correct idea:</strong> This is tautological — you cannot explain break-even by using the term ''break-even''. You must show understanding by explaining WHAT break-even means: ''the point at which total revenue covers all costs, with no profit or loss.''</p>", "question": "Why does ''it shows how many a business needs to sell to break-even'' fail as an Understanding mark?", "options": ["It only applies to businesses that sell more than one single product", "It is factually incorrect and does not relate to break-even in any real way", "It is tautological, using the term ''break-even'' to explain break-even itself", "It is too detailed and includes far more information than is needed"]}'::jsonb, '{"answer": 2, "explain": "The card explains this answer is tautological — you cannot explain break-even using the word ''break-even''; you must state what it actually means."}'::jsonb),
('business:5-4-break-even:misc:f727141d', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When asked about a limitation, students say ''the figures might be wrong'' or ''it is inaccurate''.</p><p><strong>✅ The correct idea:</strong> This is too vague and scores zero marks. You must explain WHY the figures could be wrong — e.g., ''A new competitor could force the business to lower its price, reducing contribution per unit and raising the real break-even output above the forecast.''</p>", "question": "Why does ''the figures might be wrong'' fail as an answer about a limitation?", "options": ["It correctly identifies the limitation without needing any more detail", "It is too vague — you must explain WHY the figures could be wrong", "It is completely incorrect, since break-even figures are never wrong", "It only applies to businesses that use a graph, not a formula"]}'::jsonb, '{"answer": 1, "explain": "The card explains this answer is too vague and scores zero — you must explain why the figures could be wrong, e.g. a new competitor forcing a price cut."}'::jsonb),
('business:5-4-break-even:misc:4bddfdb9', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse ''margin of safety'' with ''profit''.</p><p><strong>✅ The correct idea:</strong> The margin of safety is measured in UNITS (actual sales minus break-even sales). It shows how far output can fall before a loss is made. Profit is a financial value in £ (TR minus TC) — a completely different calculation.</p>", "question": "What is the key difference between margin of safety and profit?", "options": ["Margin of safety can only be calculated once a business has already made a profit", "Margin of safety is measured in units, while profit is a financial value in pounds", "Profit is measured in units, while margin of safety is a financial value in pounds", "Margin of safety and profit are simply two different names for the same figure"]}'::jsonb, '{"answer": 1, "explain": "The card explains margin of safety (actual sales minus break-even sales) is measured in units, while profit (TR minus TC) is a financial value in pounds — a completely different calculation."}'::jsonb),
('business:5-4-break-even:misc:1888b62c', 'business', 'business:5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think any business can use break-even analysis equally well.</p><p><strong>✅ The correct idea:</strong> Break-even works best for businesses selling a SINGLE product at a fixed price. For businesses with multiple products at varying prices and costs, break-even is difficult to calculate accurately and much less useful as a planning tool.</p>", "question": "For which type of business does break-even analysis work best, according to this card?", "options": ["A business that has no variable costs of any kind to consider", "A business selling many different products at many different prices", "A business that has no fixed costs of any kind to consider", "A business selling a single product at one fixed price"]}'::jsonb, '{"answer": 3, "explain": "The card explains break-even works best for a single-product business at a fixed price; multi-product businesses with varying prices and costs find it far less useful."}'::jsonb)
